    end
    
    subgraph "Infrastructure Layer"
        I[Docker Compose]
        J[Test Database]
        K[Test Redis]
        L[Test NATS]
    end
    
    subgraph "Reporting Layer"
        M[Coverage Reporter]
        N[Test Results]
        O[Flaky Test Detector]
        P[CI/CD Integration]
    end
    
    A --> E
    B --> F
    C --> E
    D --> F
    
    E --> G
    F --> G
