```

### Testing Layers

The framework implements a pyramid testing strategy with multiple layers:

1. **Unit Tests (Base Layer)**: Fast, isolated tests for individual functions, components, and methods
2. **Integration Tests (Middle Layer)**: Tests for service interactions, API endpoints, and database operations
3. **E2E Tests (Top Layer)**: Complete user flow tests from UI to database
4. **Performance Tests (Specialized)**: Load, stress, and endurance tests
5. **Property-Based Tests (Specialized)**: Generative tests for parsers, serializers, and data transformations

### Component Architecture

#### Frontend Testing Stack

```mermaid
graph LR
    A[React Components] --> B[Vitest + React Testing Library]
    C[Custom Hooks] --> D[@testing-library/react-hooks]
    E[Zustand Stores] --> B
    F[API Calls] --> G[MSW - Mock Service Worker]
    
    B --> H[Coverage Reporter]
    D --> H
    G --> H
    
    H --> I[Istanbul/NYC Format]
    I --> J[CI/CD Pipeline]
```

**Technology Stack:**
- **Test Runner**: Vitest (fast, Vite-native, ESM support)
- **Component Testing**: React Testing Library (accessibility-focused queries)
- **Hook Testing**: @testing-library/react-hooks
- **API Mocking**: MSW (Mock Service Worker) for intercepting HTTP requests
- **E2E Testing**: Playwright (cross-browser, auto-wait, parallel execution)
- **Visual Testing**: Percy or Chromatic for visual regression
- **Coverage**: Vitest coverage with c8 (V8 coverage)

#### Backend Testing Stack

```mermaid
graph LR
    A[HTTP Handlers] --> B[httptest Package]
    C[Business Logic] --> D[testify/assert]
    E[Repositories] --> F[sqlmock]
    G[gRPC Services] --> H[grpc-testing]
    
    B --> I[go test -cover]
    D --> I
    F --> I
    H --> I
    
    I --> J[Coverage Report]
    J --> K[CI/CD Pipeline]
```

**Technology Stack:**
- **Test Runner**: Go test (built-in, table-driven tests)
- **Assertions**: testify/assert and testify/require
- **Mocking**: testify/mock for interfaces, sqlmock for database
- **HTTP Testing**: httptest package for HTTP handlers
- **Integration**: Docker Compose for test infrastructure
- **Performance**: k6 for load testing
- **Coverage**: go test -cover with HTML reports

## Components and Interfaces

### 1. Frontend Test Utilities

#### Component Test Helper

```typescript
// test-utils/component-test-helper.ts
import { render, RenderOptions } from '@testing-library/react';
import { ReactElement } from 'react';
import { BrowserRouter } from 'react-router-dom';

interface CustomRenderOptions extends RenderOptions {
  initialRoute?: string;
  withRouter?: boolean;
}

export function renderWithProviders(
  ui: ReactElement,
  options?: CustomRenderOptions
) {
  const { initialRoute = '/', withRouter = true, ...renderOptions } = options || {};
  
  const Wrapper = ({ children }: { children: React.ReactNode }) => {
    if (withRouter) {
      window.history.pushState({}, 'Test page', initialRoute);
      return <BrowserRouter>{children}</BrowserRouter>;
    }
    return <>{children}</>;
  };

  return render(ui, { wrapper: Wrapper, ...renderOptions });
}
```

#### Store Test Helper

```typescript
// test-utils/store-test-helper.ts
import { StoreApi, UseBoundStore } from 'zustand';

export function resetStore<T>(store: UseBoundStore<StoreApi<T>>) {
  const initialState = store.getState();
  store.setState(initialState, true);
}

export function createMockStore<T>(initialState: Partial<T>) {
  return {
    getState: () => initialState as T,
    setState: jest.fn(),
    subscribe: jest.fn(),
    destroy: jest.fn(),
  };
}
```

#### API Mock Helper

```typescript
// test-utils/api-mock-helper.ts
import { rest } from 'msw';
import { setupServer } from 'msw/node';

export const mockApiHandlers = [
  rest.get('/api/devices', (req, res, ctx) => {
    return res(ctx.json({ devices: [] }));
  }),
  rest.post('/api/auth/login', (req, res, ctx) => {
    return res(ctx.json({ token: 'mock-token' }));
  }),
];

export const server = setupServer(...mockApiHandlers);

export function mockApiResponse(endpoint: string, response: any, status = 200) {
  server.use(
    rest.get(endpoint, (req, res, ctx) => {
      return res(ctx.status(status), ctx.json(response));
    })
  );
}
```

### 2. Backend Test Utilities

#### HTTP Test Helper

```go
// pkg/testutil/http_helper.go
package testutil

import (
    "bytes"
    "encoding/json"
    "net/http"
    "net/http/httptest"
    "testing"
)

type HTTPTestHelper struct {
    t *testing.T
}

func NewHTTPTestHelper(t *testing.T) *HTTPTestHelper {
    return &HTTPTestHelper{t: t}
}

func (h *HTTPTestHelper) MakeRequest(
    method, path string,
    body interface{},
    handler http.HandlerFunc,
) *httptest.ResponseRecorder {
    var reqBody []byte
    var err error
    
    if body != nil {
        reqBody, err = json.Marshal(body)
        if err != nil {
            h.t.Fatalf("Failed to marshal request body: %v", err)
        }
    }
    
    req := httptest.NewRequest(method, path, bytes.NewBuffer(reqBody))
    req.Header.Set("Content-Type", "application/json")
    
    rr := httptest.NewRecorder()
    handler.ServeHTTP(rr, req)
    
    return rr
}

func (h *HTTPTestHelper) AssertStatusCode(rr *httptest.ResponseRecorder, expected int) {
    if rr.Code != expected {
        h.t.Errorf("Expected status code %d, got %d", expected, rr.Code)
    }
}

func (h *HTTPTestHelper) ParseResponse(rr *httptest.ResponseRecorder, v interface{}) {
    if err := json.Unmarshal(rr.Body.Bytes(), v); err != nil {
        h.t.Fatalf("Failed to parse response: %v", err)
    }
}
```

#### Database Test Helper

```go
// pkg/testutil/db_helper.go
package testutil

import (
    "database/sql"
    "fmt"
    "testing"
    
    "github.com/DATA-DOG/go-sqlmock"
)

type DBTestHelper struct {
    DB   *sql.DB
    Mock sqlmock.Sqlmock
    t    *testing.T
}

func NewDBTestHelper(t *testing.T) *DBTestHelper {
    db, mock, err := sqlmock.New()
    if err != nil {
        t.Fatalf("Failed to create sqlmock: %v", err)
    }
    
    return &DBTestHelper{
        DB:   db,
        Mock: mock,
        t:    t,
    }
}

func (h *DBTestHelper) Close() {
    h.DB.Close()
}

func (h *DBTestHelper) ExpectQuery(query string) *sqlmock.ExpectedQuery {
    return h.Mock.ExpectQuery(query)
}

func (h *DBTestHelper) ExpectExec(query string) *sqlmock.ExpectedExec {
    return h.Mock.ExpectExec(query)
}

func (h *DBTestHelper) AssertExpectations() {
    if err := h.Mock.ExpectationsWereMet(); err != nil {
        h.t.Errorf("Unfulfilled expectations: %v", err)
    }
}
```

