### 3. Test Data Manager

#### Fixture Loader

```typescript
// test-utils/fixture-loader.ts
import fs from 'fs';
import path from 'path';

export class FixtureLoader {
  private fixturesDir: string;

  constructor(fixturesDir = './test/fixtures') {
    this.fixturesDir = fixturesDir;
  }

  load<T>(fixtureName: string): T {
    const fixturePath = path.join(this.fixturesDir, `${fixtureName}.json`);
    
    if (!fs.existsSync(fixturePath)) {
      throw new Error(`Fixture not found: ${fixturePath}`);
    }
    
    const content = fs.readFileSync(fixturePath, 'utf-8');
    return JSON.parse(content) as T;
  }

  loadMultiple<T>(fixtureNames: string[]): T[] {
    return fixtureNames.map(name => this.load<T>(name));
  }
}
```

