    if deviceID, ok := overrides["device_id"].(string); ok {
        device.DeviceID = deviceID
    }
    if model, ok := overrides["model"].(string); ok {
        device.Model = model
    }
    if status, ok := overrides["status"].(string); ok {
        device.Status = status
