#### Environment Setup Script

```typescript
// test-utils/environment-setup.ts
import { exec } from 'child_process';
import { promisify } from 'util';

const execAsync = promisify(exec);

export class TestEnvironment {
  private static instance: TestEnvironment;
  private isSetup = false;

  private constructor() {}

  static getInstance(): TestEnvironment {
    if (!TestEnvironment.instance) {
      TestEnvironment.instance = new TestEnvironment();
    }
    return TestEnvironment.instance;
  }

  async setup(): Promise<void> {
    if (this.isSetup) {
      return;
    }

    console.log('Starting test environment...');
    
    try {
      // Start Docker Compose services
      await execAsync('docker-compose -f docker-compose.test.yml up -d');
      
      // Wait for health checks
      await this.waitForHealthChecks();
      
      // Run migrations
      await this.runMigrations();
      
      this.isSetup = true;
      console.log('Test environment ready');
    } catch (error) {
      console.error('Failed to setup test environment:', error);
      throw error;
    }
  }

  async teardown(): Promise<void> {
    if (!this.isSetup) {
      return;
    }

    console.log('Stopping test environment...');
    
    try {
      await execAsync('docker-compose -f docker-compose.test.yml down -v');
      this.isSetup = false;
      console.log('Test environment stopped');
    } catch (error) {
      console.error('Failed to teardown test environment:', error);
      throw error;
    }
  }

  private async waitForHealthChecks(maxRetries = 12, interval = 5000): Promise<void> {
    for (let i = 0; i < maxRetries; i++) {
      try {
        const { stdout } = await execAsync(
          'docker-compose -f docker-compose.test.yml ps --format json'
        );
        
        const services = JSON.parse(stdout);
        const allHealthy = services.every((s: any) => s.Health === 'healthy');
        
        if (allHealthy) {
          return;
        }
      } catch (error) {
        // Continue retrying
      }
      
      await new Promise(resolve => setTimeout(resolve, interval));
    }
    
    throw new Error('Health checks failed after maximum retries');
  }

  private async runMigrations(): Promise<void> {
    // Run database migrations
    await execAsync('npm run migrate:test');
  }
}
```

