// services/auth-service/integration/auth_integration_test.go
package integration

import (
    "bytes"
    "encoding/json"
    "net/http"
    "testing"
    
    "github.com/stretchr/testify/assert"
    "github.com/stretchr/testify/require"
)

func TestAuthIntegration_LoginFlow(t *testing.T) {
    // Setup test environment
    env := SetupTestEnvironment(t)
    defer env.Teardown()
    
    // Create test user in database
    user := env.Factory.CreateUser(map[string]interface{}{
        "email":    "integration@example.com",
        "password": "hashed_password",
    })
    env.DB.InsertUser(user)
    
    // Test login
    loginReq := map[string]string{
        "email":    "integration@example.com",
        "password": "password123",
    }
    body, _ := json.Marshal(loginReq)
    
    resp, err := http.Post(
        env.BaseURL+"/auth/login",
        "application/json",
        bytes.NewBuffer(body),
    )
    require.NoError(t, err)
    defer resp.Body.Close()
    
    // Verify response
    assert.Equal(t, http.StatusOK, resp.StatusCode)
    
    var loginResp map[string]interface{}
    json.NewDecoder(resp.Body).Decode(&loginResp)
    
    assert.NotEmpty(t, loginResp["token"])
    assert.Equal(t, user.ID, loginResp["user_id"])
}
```

