// apps/admin-panel/src/components/__tests__/DeviceList.test.tsx
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { DeviceList } from '../DeviceList';
import { TestDataFactory } from '@/test-utils/factories';

describe('DeviceList', () => {
  const factory = new TestDataFactory();
  
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should render device list with correct data', async () => {
    const devices = factory.createDevices(3);
    
    render(<DeviceList devices={devices} />);
    
    for (const device of devices) {
      expect(screen.getByText(device.model)).toBeInTheDocument();
      expect(screen.getByText(device.status)).toBeInTheDocument();
    }
  });

  it('should filter devices by status', async () => {
    const devices = [
      factory.createDevice({ status: 'online' }),
      factory.createDevice({ status: 'offline' }),
      factory.createDevice({ status: 'online' }),
    ];
    
    render(<DeviceList devices={devices} />);
    
    const filterSelect = screen.getByLabelText('Filter by status');
    await userEvent.selectOptions(filterSelect, 'online');
    
    await waitFor(() => {
      const visibleDevices = screen.getAllByRole('row');
      expect(visibleDevices).toHaveLength(2); // 2 online devices
    });
  });

  it('should handle device selection', async () => {
    const devices = factory.createDevices(2);
    const onSelect = vi.fn();
    
    render(<DeviceList devices={devices} onSelect={onSelect} />);
    
    const firstDevice = screen.getAllByRole('row')[0];
    await userEvent.click(firstDevice);
    
    expect(onSelect).toHaveBeenCalledWith(devices[0].device_id);
  });
});
