### Backend Handler Test

```go
// services/device-service/internal/handlers/device_handler_test.go
package handlers

import (
    "bytes"
    "encoding/json"
    "net/http"
    "net/http/httptest"
    "testing"
    
    "github.com/audira-grid/pkg/testutil"
    "github.com/stretchr/testify/assert"
    "github.com/stretchr/testify/mock"
)

func TestDeviceHandler_ListDevices(t *testing.T) {
    tests := []struct {
        name           string
        tenantID       string
        mockDevices    []Device
        mockError      error
        expectedStatus int
        expectedCount  int
    }{
        {
            name:     "successful device listing",
            tenantID: "tenant-123",
            mockDevices: []Device{
                {ID: "device-1", Model: "Samsung S21"},
                {ID: "device-2", Model: "Pixel 6"},
            },
            mockError:      nil,
            expectedStatus: http.StatusOK,
            expectedCount:  2,
        },
        {
            name:           "empty device list",
            tenantID:       "tenant-456",
            mockDevices:    []Device{},
            mockError:      nil,
            expectedStatus: http.StatusOK,
            expectedCount:  0,
        },
        {
            name:           "database error",
            tenantID:       "tenant-789",
            mockDevices:    nil,
            mockError:      ErrDatabaseConnection,
            expectedStatus: http.StatusInternalServerError,
            expectedCount:  0,
        },
    }
    
    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            // Arrange
            mockService := new(MockDeviceService)
            mockService.On("ListDevices", mock.Anything, tt.tenantID).
                Return(tt.mockDevices, tt.mockError)
            
            handler := NewDeviceHandler(mockService)
            
            req := httptest.NewRequest(http.MethodGet, "/devices", nil)
            req.Header.Set("X-Tenant-ID", tt.tenantID)
            rr := httptest.NewRecorder()
            
            // Act
            handler.ListDevices(rr, req)
            
            // Assert
            assert.Equal(t, tt.expectedStatus, rr.Code)
            
            if tt.expectedStatus == http.StatusOK {
                var response map[string][]Device
                json.NewDecoder(rr.Body).Decode(&response)
                assert.Len(t, response["devices"], tt.expectedCount)
            }
            
            mockService.AssertExpectations(t)
        })
    }
}
```

### Integration Test

```go
// services/device-service/integration/device_integration_test.go
package integration

import (
    "bytes"
    "encoding/json"
    "net/http"
    "testing"
    
    "github.com/audira-grid/pkg/testutil"
    "github.com/stretchr/testify/assert"
    "github.com/stretchr/testify/require"
)

func TestDeviceIntegration_CreateAndRetrieve(t *testing.T) {
    // Setup
    env := testutil.SetupTestEnvironment(t)
    defer env.Teardown()
    
    tenantID := "tenant-integration-test"
    
    // Create device
    createReq := map[string]interface{}{
        "model":      "Samsung Galaxy S21",
        "os_version": "Android 13",
        "tenant_id":  tenantID,
    }
    body, _ := json.Marshal(createReq)
    
    resp, err := http.Post(
        env.BaseURL+"/devices",
        "application/json",
        bytes.NewBuffer(body),
    )
    require.NoError(t, err)
    defer resp.Body.Close()
    
    assert.Equal(t, http.StatusCreated, resp.StatusCode)
    
    var createResp map[string]interface{}
    json.NewDecoder(resp.Body).Decode(&createResp)
    deviceID := createResp["device_id"].(string)
    
    // Retrieve device
    getResp, err := http.Get(env.BaseURL + "/devices/" + deviceID)
    require.NoError(t, err)
    defer getResp.Body.Close()
    
    assert.Equal(t, http.StatusOK, getResp.StatusCode)
    
    var device map[string]interface{}
    json.NewDecoder(getResp.Body).Decode(&device)
    
    assert.Equal(t, deviceID, device["device_id"])
    assert.Equal(t, "Samsung Galaxy S21", device["model"])
    assert.Equal(t, tenantID, device["tenant_id"])
}
